New Row.code:
// Insert a row into a MySQL table.
insert(
  'users',
  { name: 'Elodie', email: 'elodie@example.org', age: 31 }
);

Update Row.code:
// Update a row using a parameterised query.
// MySQL placeholders are positional `?` values.
sql(
  'UPDATE users SET email = ?, updated_at = NOW() WHERE id = ?;',
  { values: [$.data.email, $.data.id] }
);

Find Row.code:
// Fetch one row by equality filter.
sql(
  'SELECT * FROM users WHERE email = ? LIMIT 1;',
  { values: [$.data.email] }
);

Find Row via Custom Query.code:
// Run a custom SELECT.
sql(
  'SELECT id, name, email FROM users WHERE created_at > ? ORDER BY id;',
  { values: ['2026-01-01'] }
);
